select
id, t.user_id, ticket_type, t.status, description, ticket_title ,t.create_time,su.nick_name as createUser
from ticket t
left join sys_user su on t.user_id=su.user_id
where 1=1 and is_deleted = 0

    and t.user_id = #{userId}


    and id = #{dto.id}


    and ticket_title like concat('%', #{dto.ticketTitle}, '%')


